//! emit-dict-wire-hex — Rust bin that emits a dict-mode wire blob as hex.
//!
//! Constructs a synthetic dictionary (16 entries × 32 bytes of known
//! patterns), writes it to a temp .bwdict file, sets GNOSIS_RESIDUAL_DICT
//! to that path, then encodes a deterministic Float32Array via
//! amplituhedron_wire::encode_replay_response (which routes through
//! residual_dict::encode_residual_with_dict).
//!
//! Stdout: a single line of hex, no whitespace.
//! Stderr: the dictionary's hex representation (so the TS verifier can
//!         materialize the same dict for decode).
//!
//! Usage:
//!   cargo run --release --bin emit-dict-wire-hex
//!
//! Pair: scripts/cross-lang-dict-fixture.ts validates byte-for-byte
//! agreement of the dict-mode path. The plain (no-dict) variant is
//! emit-wire-hex + scripts/cross-lang-wire-fixture.ts.

use distributed_inference::amplituhedron_wire::{
    encode_replay_response, AmplituhedronReplayBinary,
};
use std::fs::File;
use std::io::Write;

fn main() {
    let hidden_dim: usize = 3584;

    // Synthetic dictionary: 16 entries × 32 bytes of known patterns.
    // Layout matches residual_dict.rs reader expectations: 4-byte magic
    // "BWDC", u32 version=1, u32 entry_count, u32 entry_len, then
    // entry_count * entry_len bytes of body.
    let entry_count: u32 = 16;
    let entry_len: u32 = 32;
    let mut dict_bytes: Vec<u8> = Vec::new();
    dict_bytes.extend_from_slice(b"BWDC");
    dict_bytes.extend_from_slice(&1u32.to_le_bytes());
    dict_bytes.extend_from_slice(&entry_count.to_le_bytes());
    dict_bytes.extend_from_slice(&entry_len.to_le_bytes());
    for i in 0..entry_count {
        for j in 0..entry_len {
            dict_bytes.push((i as u8).wrapping_add(j as u8).wrapping_mul(7));
        }
    }

    // Write to temp file.
    let dict_path = std::env::temp_dir().join("emit-dict-wire-hex.bwdict");
    File::create(&dict_path)
        .expect("create dict tempfile")
        .write_all(&dict_bytes)
        .expect("write dict bytes");

    // Print dict hex to stderr so the TS verifier can rebuild it.
    let dict_hex: String = dict_bytes.iter().map(|b| format!("{:02x}", b)).collect();
    eprintln!("{}", dict_hex);

    // Activate the dict for this process.
    // SAFETY: Rust 2024 marks `std::env::set_var` unsafe because mutating
    // process env is not thread-safe relative to libc readers. This bin is
    // single-threaded and sets the var before any reader (encode_residual_
    // with_dict, called below) touches it.
    unsafe {
        std::env::set_var("GNOSIS_RESIDUAL_DICT", &dict_path);
    }

    // Build deterministic residual via LCG. Seed is 0xC0DEC0DE — distinct
    // from the plain fixture's 0xCAFEBEEF so the two fixtures don't share
    // a residual.
    let mut state: u64 = 0xC0DEC0DE;
    let mut residual: Vec<f32> = Vec::with_capacity(hidden_dim);
    for _ in 0..hidden_dim {
        state = state
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        let u = (state >> 32) as u32;
        residual.push(u as f32 / u32::MAX as f32);
    }

    let reply = AmplituhedronReplayBinary {
        hit: true,
        tail_len: residual.len() as u32,
        kv_slab_len: 0,
        tail_residual: Some(residual),
    };

    let bytes = encode_replay_response(&reply);
    let hex: String = bytes.iter().map(|b| format!("{:02x}", b)).collect();
    print!("{}", hex);
}
